/* ================================
   MyCart Page Styling (Orange Theme)
================================ */

.mycart-container {
  display: flex;
  gap: 1rem;
  padding: 1rem;
  align-items: flex-start;
  min-height: 100vh;
  background: linear-gradient(to right, #fff7ed, #ffffff); /* optional page background */
}

/* LEFT – Appointment Form */
.appointment-card {
  width: 50%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(8px);
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
  padding: 1rem;
}

.appointment-card h1 {
  color: #80102b;
  font-size: 1.4rem;
  font-weight: 700;
  text-align: center;
}

/* Orange Gradient Header */
.appointment-card .card-header {
  min-height: 80px;
  background: linear-gradient(to right, #fbbf24, #f97316, #fbbf24);
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 10px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.15);
  color: white;
  font-weight: 700;
  font-size: 1.5rem;
}

/* Separator */
.separator {
  border-top: 2px solid #ddd;
  margin: 0.8rem 0;
}

/* Location dropdown */
.location-select {
  display: flex;
  align-items: center;
  border: 1px solid #f97316;
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  transition: all 0.3s ease;
  background: rgba(255, 255, 255, 0.7);
  backdrop-filter: blur(4px);
}

.location-select:focus-within {
  border-color: #f97316;
  box-shadow: 0 0 0 2px rgba(249, 115, 22, 0.2);
}

.location-select select {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  color: #f97316;
  font-weight: 500;
}

/* Footer buttons */
.appointment-actions {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin-top: 1rem;
}

.appointment-actions button {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  background: linear-gradient(to right, #fbbf24, #f97316, #fbbf24);
  color: #fff;
  font-weight: 600;
  padding: 10px 20px;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;
}

.appointment-actions button:hover {
  transform: scale(1.05);
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.2);
}

/* RIGHT – Payment / Receipt */
.payment-card {
  width: 50%;
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(8px);
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
  padding: 1rem;
}

/* Orange Gradient Header for Payment Card */
.payment-card .card-header {
  min-height: 80px;
  background: linear-gradient(to right, #fbbf24, #f97316, #fbbf24);
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 10px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.15);
  color: white;
  font-weight: 700;
  font-size: 1.5rem;
}

.payment-card img {
  display: block;
  margin: 0 auto;
  border-radius: 12px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.15);
}

.payment-summary {
  width: 90%;
  margin: 1rem auto;
}

.payment-summary h1 {
  color: orange;
  font-size: 1.2rem;
  font-weight: 700;
  text-align: center;
}

.payment-summary div {
  display: flex;
  justify-content: space-between;
  margin: 0.4rem 0;
  font-size: 1rem;
}

.payment-summary button {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  background: linear-gradient(to right, #fbbf24, #f97316, #fbbf24);
  color: #fff;
  font-weight: 600;
  padding: 10px 20px;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;
}

.payment-summary button:hover {
  transform: scale(1.05);
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.2);
}

/* Notes */
.note-text {
  font-size: 0.9rem;
  color: red;
  margin-top: 0.75rem;
  font-weight: 600;
  text-align: center;
}

/* ================================
   PRINT STYLES
================================ */

.print-area {
  padding: 1rem;
}

@media print {
  body * {
    visibility: hidden;
  }

  .print-area,
  .print-area * {
    visibility: visible;
  }

  .print-area {
    position: absolute;
    left: 0;
    top: 0;
    width: 100%;
  }
}

/* ================================
   RESPONSIVE
================================ */

@media (max-width: 1024px) {
  .mycart-container {
    flex-direction: column;
  }

  .appointment-card,
  .payment-card {
    width: 100%;
    min-height: auto;
  }
}
